/**
 * Tests for reset-password.js (CLI password reset script)
 * Uses syntax validation instead of require() since the script
 * executes an IIFE with process.exit() at load time.
 * @generated by P#105
 */
'use strict';

const fs = require('fs');
const path = require('path');
const vm = require('vm');

describe('reset-password.js', () => {
  const filePath = path.join(__dirname, '..', '..', 'reset-password.js');
  let source;

  beforeAll(() => {
    source = fs.readFileSync(filePath, 'utf8');
  });

  test('file should exist', () => {
    expect(fs.existsSync(filePath)).toBe(true);
  });

  test('should be valid JavaScript syntax', () => {
    expect(() => {
      new vm.Script(source, { filename: 'reset-password.js' });
    }).not.toThrow();
  });

  test('should require dotenv', () => {
    expect(source).toMatch(/require\s*\(\s*['"]dotenv['"]\s*\)/);
  });

  test('should require mongoose', () => {
    expect(source).toMatch(/require\s*\(\s*['"]mongoose['"]\s*\)/);
  });

  test('should require bcryptjs', () => {
    expect(source).toMatch(/require\s*\(\s*['"]bcryptjs['"]\s*\)/);
  });

  test('should have run() function', () => {
    expect(source).toMatch(/(?:async\s+)?function\s+run/);
  });

  test('should connect to MongoDB', () => {
    expect(source).toMatch(/mongoose\.connect/);
  });

  test('should hash the new password', () => {
    expect(source).toMatch(/bcrypt\.hash/);
  });
});
